components.css:
dialog {
  border: none;
  border-radius: var(--a-radius-lg);
  padding: var(--a-space-2xl);
  max-width: 500px;
  box-shadow: 0 20px 40px rgba(0, 0, 0, 0.3);
}

dialog::backdrop {
  background: rgba(0, 0, 0, 0.5);
  backdrop-filter: blur(4px);
}

dialog footer {
  display: flex;
  gap: var(--a-space-md);
  justify-content: flex-end;
  margin-top: var(--a-space-lg);
}

button[data-tooltip]::after {
  content: attr(data-tooltip);
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  padding: var(--a-space-xs) var(--a-space-sm);
  background: var(--a-text-main);
  color: var(--a-surface-base);
  border-radius: var(--a-radius-sm);
  font-size: var(--a-text-xs);
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--a-transition-base);
}

button[data-tooltip]:hover::after {
  opacity: 1;
}

div[popover] {
  background: var(--a-surface-raised);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  padding: var(--a-space-lg);
  box-shadow: var(--a-shadow-lg);
  max-width: 300px;
}

:popover-open {
  border-color: var(--a-primary);
}

.spinner {
  width: 40px;
  height: 40px;
  border: 4px solid var(--a-surface-overlay);
  border-top-color: var(--a-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

progress {
  width: 100%;
  height: 8px;
  border-radius: var(--a-radius-sm);
  border: none;
  background: var(--a-surface-overlay);
  overflow: hidden;
}

progress::-webkit-progress-bar {
  background: var(--a-surface-overlay);
}

progress::-webkit-progress-value {
  background: var(--a-primary);
  border-radius: var(--a-radius-sm);
}

progress::-moz-progress-bar {
  background: var(--a-primary);
  border-radius: var(--a-radius-sm);
}

details {
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  padding: var(--a-space-md);
  margin-bottom: var(--a-space-md);
}

summary {
  cursor: pointer;
  font-weight: var(--a-font-weight-semibold);
  user-select: none;
  color: var(--a-primary);
}

summary::marker {
  color: var(--a-primary);
}

details[open] {
  background: var(--a-surface-overlay);
}

details > p {
  margin-top: var(--a-space-md);
}

select {
  width: 100%;
  padding: var(--a-space-sm) var(--a-space-md);
  background: var(--a-surface-raised);
  color: var(--a-text-main);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  font-size: var(--a-text-base);
  cursor: pointer;
  transition: all var(--a-transition-base);
}

select:focus {
  outline: none;
  border-color: var(--a-primary);
  box-shadow: 0 0 0 3px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

.toggle {
  display: flex;
  align-items: center;
  gap: var(--a-space-md);
  cursor: pointer;
}

.toggle input[type="checkbox"] {
  appearance: none;
  width: 48px;
  height: 24px;
  background: var(--a-surface-overlay);
  border-radius: 12px;
  border: none;
  cursor: pointer;
  transition: background var(--a-transition-base);
  position: relative;
}

.toggle input[type="checkbox"]::after {
  content: '';
  position: absolute;
  width: 20px;
  height: 20px;
  background: white;
  border-radius: 50%;
  top: 2px;
  left: 2px;
  transition: left var(--a-transition-base);
}

.toggle input[type="checkbox"]:checked {
  background: var(--a-primary);
}

.toggle input[type="checkbox"]:checked::after {
  left: 26px;
}
